                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V24, NDS_VEC_V30);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V24, NDS_VEC_V31);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V25, NDS_VEC_V28);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V25, NDS_VEC_V29);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V25, NDS_VEC_V30);
