                NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V26, NDS_VEC_V31);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V27, NDS_VEC_V28);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V27, NDS_VEC_V29);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V27, NDS_VEC_V30);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V27, NDS_VEC_V31);
