            // Small K (< maxvl_per_loop): zero accumulators conventionally; tail loop handles compute.
            NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
