        NDS_VEC_VSB_V(NDS_VEC_V0, out);
        NDS_VEC_VSB_V(NDS_VEC_V4, pOut2);
        NDS_VEC_VSB_V(NDS_VEC_V8, pOut3);
        NDS_VEC_VSB_V(NDS_VEC_V12, pOut4);
