    }

    //extra process for the case of elements to be dot producted is not a multiple of 4
    if(col_count > 0)
    {
        //clean pixel buffers to avoid junk in tail affecting vd4dots
        long tmp_avl;
        tmp_avl = col_count + 3;
        NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
        NDS_VEC_VAND_VI(NDS_VEC_V21, NDS_VEC_V21, 0);
        NDS_VEC_VAND_VI(NDS_VEC_V22, NDS_VEC_V22, 0);
        NDS_VEC_VAND_VI(NDS_VEC_V23, NDS_VEC_V23, 0);

        NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_b0);
        NDS_VEC_VLE8_V(NDS_VEC_V21, ptr_b1);
        NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_b2);
        NDS_VEC_VLE8_V(NDS_VEC_V23, ptr_b3);
        NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
        NDS_VEC_VLE8_V(NDS_VEC_V17, ptr_a1);
        NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_a2);
        NDS_VEC_VLE8_V(NDS_VEC_V19, ptr_a3);
        ptr_a0 += vl;
        ptr_a1 += vl;
        ptr_a2 += vl;
        ptr_a3 += vl;

        vl = (vl + 3) >> 2;
        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
        NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
    }

    // === Reduction epilogue: 16 vredsum → pack to VL=4 → requantize ===
    // SW-pipeline Phase A loads pixel data into V31 every iteration, so we must
    // re-zero V31 here. Merge vand under the vredsum vsetvli (vand at e32 m1 is 1 cyc
    // regardless of VL; vredsum reads only V31[0]). Saves the vsetvli(vl=1) barrier.
    NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);

    // Reduce 16 accumulators to scalars in element [0]
    // pix0: ch0→v16[0], ch1→v17[0], ch2→v18[0], ch3→v19[0]
    NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0
    NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V4,  NDS_VEC_V31);  //ch1*pix0
    NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8,  NDS_VEC_V31);  //ch2*pix0
    NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V12, NDS_VEC_V31);  //ch3*pix0
    // pix1: ch0→v20[0], ch1→v21[0], ch2→v22[0], ch3→v23[0]
    NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V1,  NDS_VEC_V31);  //ch0*pix1
    NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V5,  NDS_VEC_V31);  //ch1*pix1
    NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V9,  NDS_VEC_V31);  //ch2*pix1
    NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V13, NDS_VEC_V31);  //ch3*pix1
    // pix2: ch0→v24[0], ch1→v25[0], ch2→v26[0], ch3→v27[0]
    NDS_VEC_VREDSUM_VS(NDS_VEC_V24, NDS_VEC_V2,  NDS_VEC_V31);  //ch0*pix2
    NDS_VEC_VREDSUM_VS(NDS_VEC_V25, NDS_VEC_V6,  NDS_VEC_V31);  //ch1*pix2
    NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V10, NDS_VEC_V31);  //ch2*pix2
    NDS_VEC_VREDSUM_VS(NDS_VEC_V27, NDS_VEC_V14, NDS_VEC_V31);  //ch3*pix2
    // pix3: ch0→v28[0], ch1→v29[0], ch2→v30[0], ch3→v0[0] (reuse v0, done with accumulators)
    NDS_VEC_VREDSUM_VS(NDS_VEC_V28, NDS_VEC_V3,  NDS_VEC_V31);  //ch0*pix3
    NDS_VEC_VREDSUM_VS(NDS_VEC_V29, NDS_VEC_V7,  NDS_VEC_V31);  //ch1*pix3
    NDS_VEC_VREDSUM_VS(NDS_VEC_V30, NDS_VEC_V11, NDS_VEC_V31);  //ch2*pix3
    NDS_VEC_VREDSUM_VS(NDS_VEC_V0,  NDS_VEC_V15, NDS_VEC_V31);  //ch3*pix3

    // Hoist all 3 requantize-tail vle32 above slideup batch.
    // V1 first since it has earliest consumer (first vadd after slideup batch).
    NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VLE32_V(NDS_VEC_V1, contri_buf);
    NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
    NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
    contri_buf += vl;

    // Pack 4 scalars into VL=4 vectors via vslideup
    // pix0: v16 = [ch0, ch1, ch2, ch3]
    NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V25, 1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V29, 1);
    NDS_VEC_VSETVLI(vl, 3, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V26, 2);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V30, 2);
    NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V27, 3);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V0,  3);

    // v16=pix0, v20=pix1, v24=pix2, v28=pix3 — each [ch0,ch1,ch2,ch3]

    //add extra contribution back
    NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V1);
    NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V1);
    NDS_VEC_VADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V1);
    NDS_VEC_VADD_VV(NDS_VEC_V28, NDS_VEC_V28, NDS_VEC_V1);

    //===== Quantize down =====
    NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);

    NDS_VEC_VWMUL_VV(NDS_VEC_V4,  NDS_VEC_V16, NDS_VEC_V3);
    NDS_VEC_VWMUL_VV(NDS_VEC_V6,  NDS_VEC_V20, NDS_VEC_V3);
    NDS_VEC_VWMUL_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V3);
    NDS_VEC_VWMUL_VV(NDS_VEC_V10, NDS_VEC_V28, NDS_VEC_V3);
    NDS_VEC_VNSRA_WV(NDS_VEC_V4,  NDS_VEC_V4,  NDS_VEC_V2);
    NDS_VEC_VNSRA_WV(NDS_VEC_V6,  NDS_VEC_V6,  NDS_VEC_V2);
    NDS_VEC_VNSRA_WV(NDS_VEC_V8,  NDS_VEC_V8,  NDS_VEC_V2);
    NDS_VEC_VNSRA_WV(NDS_VEC_V10, NDS_VEC_V10, NDS_VEC_V2);
    NDS_VEC_VSSRA_VI(NDS_VEC_V4,  NDS_VEC_V4,  1);
    NDS_VEC_VSSRA_VI(NDS_VEC_V6,  NDS_VEC_V6,  1);
    NDS_VEC_VSSRA_VI(NDS_VEC_V8,  NDS_VEC_V8,  1);
    NDS_VEC_VSSRA_VI(NDS_VEC_V10, NDS_VEC_V10, 1);

    // Add offset
    NDS_VEC_VADD_VX(NDS_VEC_V4,  NDS_VEC_V4,  out_offset);
    NDS_VEC_VADD_VX(NDS_VEC_V6,  NDS_VEC_V6,  out_offset);
    NDS_VEC_VADD_VX(NDS_VEC_V8,  NDS_VEC_V8,  out_offset);
    NDS_VEC_VADD_VX(NDS_VEC_V10, NDS_VEC_V10, out_offset);

    // Clamp the result. Peephole: split into all-vmax then all-vmin batches
    // (4 independent regs each) so vmin Vk is 4 instr after vmax Vk -- the
    // 3-4 cyc VALU latency is fully hidden vs. the original alternating order.
    NDS_VEC_VMAX_VX(NDS_VEC_V4,  NDS_VEC_V4,  act_min);
    NDS_VEC_VMAX_VX(NDS_VEC_V6,  NDS_VEC_V6,  act_min);
    NDS_VEC_VMAX_VX(NDS_VEC_V8,  NDS_VEC_V8,  act_min);
    NDS_VEC_VMAX_VX(NDS_VEC_V10, NDS_VEC_V10, act_min);
    NDS_VEC_VMIN_VX(NDS_VEC_V4,  NDS_VEC_V4,  act_max);
    NDS_VEC_VMIN_VX(NDS_VEC_V6,  NDS_VEC_V6,  act_max);
    NDS_VEC_VMIN_VX(NDS_VEC_V8,  NDS_VEC_V8,  act_max);
    NDS_VEC_VMIN_VX(NDS_VEC_V10, NDS_VEC_V10, act_max);

    //narrowing and store the results
    NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VNSRA_VI(NDS_VEC_V4,  NDS_VEC_V4,  0);
    NDS_VEC_VNSRA_VI(NDS_VEC_V6,  NDS_VEC_V6,  0);
    NDS_VEC_VNSRA_VI(NDS_VEC_V8,  NDS_VEC_V8,  0);
    NDS_VEC_VNSRA_VI(NDS_VEC_V10, NDS_VEC_V10, 0);
    NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VNSRA_VI(NDS_VEC_V4,  NDS_VEC_V4,  0);
    NDS_VEC_VNSRA_VI(NDS_VEC_V6,  NDS_VEC_V6,  0);
    NDS_VEC_VNSRA_VI(NDS_VEC_V8,  NDS_VEC_V8,  0);
    NDS_VEC_VNSRA_VI(NDS_VEC_V10, NDS_VEC_V10, 0);
    NDS_VEC_VSE8_V(NDS_VEC_V4,  out_0);
    NDS_VEC_VSE8_V(NDS_VEC_V6,  out_1);
    NDS_VEC_VSE8_V(NDS_VEC_V8,  out_2);
    NDS_VEC_VSE8_V(NDS_VEC_V10, out_3);
    out_0 += 4;
    out_1 += 4;
    out_2 += 4;
    out_3 += 4;
    out_scale += 4;
    out_shift += 4;

    ptr_a0 += 3 * (long)num_col_a;  // skip past channels 1,2,3
}

// === Handle remaining 2 channels (if out_tensor_ch % 4 >= 2) ===
if ((out_tensor_ch & 0x3) >= 2)
{
    const int8_t *ptr_b0 = input_b;
    const int8_t *ptr_b1 = ptr_b0 + num_col_a;
    const int8_t *ptr_b2 = ptr_b1 + num_col_a;
    const int8_t *ptr_b3 = ptr_b2 + num_col_a;
    const int8_t *ptr_a1 = ptr_a0 + num_col_a;

    NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V0,  NDS_VEC_V0,  0x0);
    NDS_VEC_VAND_VI(NDS_VEC_V1,  NDS_VEC_V1,  0x0);
    NDS_VEC_VAND_VI(NDS_VEC_V2,  NDS_VEC_V2,  0x0);
    NDS_VEC_VAND_VI(NDS_VEC_V3,  NDS_VEC_V3,  0x0);
    NDS_VEC_VAND_VI(NDS_VEC_V4,  NDS_VEC_V4,  0x0);
    NDS_VEC_VAND_VI(NDS_VEC_V5,  NDS_VEC_V5,  0x0);
    NDS_VEC_VAND_VI(NDS_VEC_V6,  NDS_VEC_V6,  0x0);
    NDS_VEC_VAND_VI(NDS_VEC_V7,  NDS_VEC_V7,  0x0);

    long col_count = num_col_a;
    while(col_count >= maxvl_per_loop)
    {
        NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
