NDS_VEC_VREDSUM_VS(NDS_VEC_V24, NDS_VEC_V8,  NDS_VEC_V31);   /* ch0*pix2 */
NDS_VEC_VREDSUM_VS(NDS_VEC_V25, NDS_VEC_V9,  NDS_VEC_V31);   /* ch1*pix2 */
NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V10, NDS_VEC_V31);   /* ch2*pix2 */
NDS_VEC_VREDSUM_VS(NDS_VEC_V27, NDS_VEC_V11, NDS_VEC_V31);   /* ch3*pix2 */
NDS_VEC_VREDSUM_VS(NDS_VEC_V28, NDS_VEC_V12, NDS_VEC_V31);   /* ch0*pix3 */
NDS_VEC_VREDSUM_VS(NDS_VEC_V29, NDS_VEC_V13, NDS_VEC_V31);   /* ch1*pix3 */
NDS_VEC_VREDSUM_VS(NDS_VEC_V30, NDS_VEC_V14, NDS_VEC_V31);   /* ch2*pix3 */
NDS_VEC_VREDSUM_VS(NDS_VEC_V0,  NDS_VEC_V15, NDS_VEC_V31);   /* ch3*pix3 (reuse V0) */

/* Pack 4 scalars into VL=4 vectors via vslideup -- match the existing per-pixel layout (V16=pix0=[ch0,ch1,ch2,ch3], V20=pix1, V24=pix2, V28=pix3). Note the original code used [V0/V4/V8/V12] for the four pixels; we now use [V16/V20/V24/V28] because the accumulators occupy V0-V15. */
NDS_VEC_VSETVLI_E32(vl, 4);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V25, 1);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V26, 2);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V27, 3);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V29, 1);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V30, 2);
NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V0,  3);   /* V0 holds ch3*pix3 */

/* Bias load -- pick a free reg. V1 is free here (V0 just slid up). Use V1 for bias to avoid colliding with V30 (which now holds pix3 ch2 pre-slideup); after slideup V30 is dead, so we can also use V30. But cleaner to use V1. */
NDS_VEC_VLW_V(NDS_VEC_V1, bias);
bias += vl;

/* Bias add */
NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V1);
NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V1);
NDS_VEC_VADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V1);
NDS_VEC_VADD_VV(NDS_VEC_V28, NDS_VEC_V28, NDS_VEC_V1);

/* pre_rshift */
NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, pre_rshift);
NDS_VEC_VSRA_VX(NDS_VEC_V20, NDS_VEC_V20, pre_rshift);
NDS_VEC_VSRA_VX(NDS_VEC_V24, NDS_VEC_V24, pre_rshift);
NDS_VEC_VSRA_VX(NDS_VEC_V28, NDS_VEC_V28, pre_rshift);

/* out_scale */
NDS_VEC_VMUL_VX(NDS_VEC_V16, NDS_VEC_V16, out_scale);
NDS_VEC_VMUL_VX(NDS_VEC_V20, NDS_VEC_V20, out_scale);
NDS_VEC_VMUL_VX(NDS_VEC_V24, NDS_VEC_V24, out_scale);
NDS_VEC_VMUL_VX(NDS_VEC_V28, NDS_VEC_V28, out_scale);

/* round */
NDS_VEC_VADD_VX(NDS_VEC_V16, NDS_VEC_V16, NN_ROUND(post_rshift));
NDS_VEC_VADD_VX(NDS_VEC_V20, NDS_VEC_V20, NN_ROUND(post_rshift));
NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, NN_ROUND(post_rshift));
NDS_VEC_VADD_VX(NDS_VEC_V28, NDS_VEC_V28, NN_ROUND(post_rshift));

/* clamp 0 */
NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0);
NDS_VEC_VMAX_VX(NDS_VEC_V20, NDS_VEC_V20, 0);
NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, 0);
NDS_VEC_VMAX_VX(NDS_VEC_V28, NDS_VEC_V28, 0);

/* narrow s32->s16 */
NDS_VEC_VSETVLI_E16(vl, 4);
NDS_VEC_VNSRA_WX(NDS_VEC_V16, NDS_VEC_V16, post_rshift);
NDS_VEC_VNSRA_WX(NDS_VEC_V20, NDS_VEC_V20, post_rshift);
NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, post_rshift);
NDS_VEC_VNSRA_WX(NDS_VEC_V28, NDS_VEC_V28, post_rshift);

/* narrow s16->u8 */
NDS_VEC_VSETVLI_E8(vl, 4);
NDS_VEC_VNCLIPU_WI(NDS_VEC_V16, NDS_VEC_V16, 0);
NDS_VEC_VNCLIPU_WI(NDS_VEC_V20, NDS_VEC_V20, 0);
NDS_VEC_VNCLIPU_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
NDS_VEC_VNCLIPU_WI(NDS_VEC_V28, NDS_VEC_V28, 0);

/* store */
NDS_VEC_VSB_V(NDS_VEC_V16, out);
NDS_VEC_VSB_V(NDS_VEC_V20, pOut2);
NDS_VEC_VSB_V(NDS_VEC_V24, pOut3);
NDS_VEC_VSB_V(NDS_VEC_V28, pOut4);
out += vl; pOut2 += vl; pOut3 += vl; pOut4 += vl;
rowCnt--;
}  /* end while(rowCnt > 0) */
```

