    //load bias
    NDS_VEC_VLW_V(NDS_VEC_V30, bias);
    bias += vl;

    //add bias back
    NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V30);
    NDS_VEC_VADD_VV(NDS_VEC_V2, NDS_VEC_V2, NDS_VEC_V30);

    //1st shift of 2-stage shift
    NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
    NDS_VEC_VSRA_VX(NDS_VEC_V2, NDS_VEC_V2, pre_rshift);

    NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
    NDS_VEC_VMUL_VX(NDS_VEC_V2, NDS_VEC_V2, out_scale);

    NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(post_rshift));
    NDS_VEC_VADD_VX(NDS_VEC_V2, NDS_VEC_V2, NN_ROUND(post_rshift));

    //scale down, clip and store the results
    NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
    NDS_VEC_VMAX_VX(NDS_VEC_V2, NDS_VEC_V2, 0);
    NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
    NDS_VEC_VNSRA_WX(NDS_VEC_V2, NDS_VEC_V2, post_rshift);
    NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VNCLIPU_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
    NDS_VEC_VNCLIPU_WI(NDS_VEC_V2, NDS_VEC_V2, 0);
    NDS_VEC_VSB_V(NDS_VEC_V0, out);
    NDS_VEC_VSB_V(NDS_VEC_V2, pOut2);
    out += vl;
    pOut2 += vl;
    src1 = pA4;
    rowCnt--;
}

